// Auto-generated demo firmware for the Renode NUCLEO-H753ZI workbench.
// Input  Red Button: Red Button SIG (CN10 pin 3 (D7 / PG12))
// Input  Green Button: Green Button SIG (CN7 pin 14 (D9/PWM / PF15))
// Input  Blue Button: Blue Button SIG (CN7 pin 9 (D14/TX3 / PD8))
// Output RGB LED 1: RGB LED 1 RED (CN9 pin 1 (A0 / PA3)) <= Red Button
// Output RGB LED 1: RGB LED 1 GREEN (CN9 pin 3 (A2 / PC3)) <= Green Button
// Output RGB LED 1: RGB LED 1 BLUE (CN9 pin 5 (A4 / PB9)) <= Blue Button

typedef unsigned int uint32_t;

#define RCC_BASE            0x58024400u
#define RCC_AHB4ENR         (*(volatile uint32_t *)(RCC_BASE + 0xE0u))

#define PERIPHERAL_PORT_ENABLE_MASK (1u << 6u) | (1u << 5u) | (1u << 3u) | (1u << 0u) | (1u << 2u) | (1u << 1u)

// Red Button: CN10 pin 3 (D7 / PG12)
#define BUTTON_0_GPIO_BASE 0x58021800u
#define BUTTON_0_PIN 12u

// Green Button: CN7 pin 14 (D9/PWM / PF15)
#define BUTTON_1_GPIO_BASE 0x58021400u
#define BUTTON_1_PIN 15u

// Blue Button: CN7 pin 9 (D14/TX3 / PD8)
#define BUTTON_2_GPIO_BASE 0x58020C00u
#define BUTTON_2_PIN 8u

// RGB LED 1: CN9 pin 1 (A0 / PA3) (mirrors Red Button)
#define LED_0_GPIO_BASE 0x58020000u
#define LED_0_PIN 3u

// RGB LED 1: CN9 pin 3 (A2 / PC3) (mirrors Green Button)
#define LED_1_GPIO_BASE 0x58020800u
#define LED_1_PIN 3u

// RGB LED 1: CN9 pin 5 (A4 / PB9) (mirrors Blue Button)
#define LED_2_GPIO_BASE 0x58020400u
#define LED_2_PIN 9u

static void enable_gpio_clocks(void) {
    RCC_AHB4ENR |= PERIPHERAL_PORT_ENABLE_MASK;
}

#define GPIO_MODER(base)    (*(volatile uint32_t *)((base) + 0x00u))
#define GPIO_PUPDR(base)    (*(volatile uint32_t *)((base) + 0x0Cu))
#define GPIO_IDR(base)      (*(volatile uint32_t *)((base) + 0x10u))
#define GPIO_BSRR(base)     (*(volatile uint32_t *)((base) + 0x18u))

static void configure_output(uint32_t base, uint32_t pin) {
    GPIO_MODER(base) &= ~(3u << (pin * 2u));
    GPIO_MODER(base) |=  (1u << (pin * 2u));
}

static void configure_input(uint32_t base, uint32_t pin) {
    GPIO_MODER(base) &= ~(3u << (pin * 2u));
    GPIO_PUPDR(base) &= ~(3u << (pin * 2u));
    GPIO_PUPDR(base) |=  (2u << (pin * 2u));
}

static void write_output(uint32_t base, uint32_t pin, int on) {
    if(on) {
        GPIO_BSRR(base) = (1u << pin);
    } else {
        GPIO_BSRR(base) = (1u << (pin + 16u));
    }
}

#define DEMO_UART_BASE      0x40004400u
#define DEMO_UART_CR1       (*(volatile uint32_t *)(DEMO_UART_BASE + 0x00u))
#define DEMO_UART_BRR       (*(volatile uint32_t *)(DEMO_UART_BASE + 0x0Cu))
#define DEMO_UART_ISR       (*(volatile uint32_t *)(DEMO_UART_BASE + 0x1Cu))
#define DEMO_UART_RDR       (*(volatile uint32_t *)(DEMO_UART_BASE + 0x24u))
#define DEMO_UART_TDR       (*(volatile uint32_t *)(DEMO_UART_BASE + 0x28u))
#define DEMO_UART_CR1_UE    (1u << 0u)
#define DEMO_UART_CR1_RE    (1u << 2u)
#define DEMO_UART_CR1_TE    (1u << 3u)
#define DEMO_UART_ISR_RXNE  (1u << 5u)
#define DEMO_UART_ISR_TXE   (1u << 7u)

static void demo_uart_init(void) {
    DEMO_UART_BRR = 0x8Bu;
    DEMO_UART_CR1 = DEMO_UART_CR1_UE | DEMO_UART_CR1_RE | DEMO_UART_CR1_TE;
}

static void demo_uart_write_char(char value) {
    for(uint32_t guard = 0; guard < 1024u && (DEMO_UART_ISR & DEMO_UART_ISR_TXE) == 0u; guard++) {
    }
    DEMO_UART_TDR = (uint32_t)(unsigned char)value;
}

static int demo_uart_read_char(void) {
    if((DEMO_UART_ISR & DEMO_UART_ISR_RXNE) == 0u) {
        return -1;
    }
    return (int)(DEMO_UART_RDR & 0xFFu);
}

static void demo_uart_write_string(const char *value) {
    while(*value) {
        demo_uart_write_char(*value++);
    }
}

static int read_input(uint32_t base, uint32_t pin) {
    return (GPIO_IDR(base) & (1u << pin)) != 0;
}

int main(void) {
    enable_gpio_clocks();
    demo_uart_init();
    demo_uart_write_string("Renode Wokwi UART ready on NUCLEO-H753ZI\r\n");
    configure_output(LED_0_GPIO_BASE, LED_0_PIN);
    configure_output(LED_1_GPIO_BASE, LED_1_PIN);
    configure_output(LED_2_GPIO_BASE, LED_2_PIN);
    configure_input(BUTTON_0_GPIO_BASE, BUTTON_0_PIN);
    configure_input(BUTTON_1_GPIO_BASE, BUTTON_1_PIN);
    configure_input(BUTTON_2_GPIO_BASE, BUTTON_2_PIN);
    int led_previous_0 = -1;
    int led_previous_1 = -1;
    int led_previous_2 = -1;
    // No generated blink outputs.

    while(1) {

        const int button_state_0 = read_input(BUTTON_0_GPIO_BASE, BUTTON_0_PIN);
        const int button_state_1 = read_input(BUTTON_1_GPIO_BASE, BUTTON_1_PIN);
        const int button_state_2 = read_input(BUTTON_2_GPIO_BASE, BUTTON_2_PIN);
        const int led_state_0 = button_state_0;
        write_output(LED_0_GPIO_BASE, LED_0_PIN, led_state_0);
        if(led_previous_0 != led_state_0) {
            led_previous_0 = led_state_0;
            demo_uart_write_string("RGB LED 1 RED ");
            demo_uart_write_string(led_state_0 ? "ON\r\n" : "OFF\r\n");
        }
        const int led_state_1 = button_state_1;
        write_output(LED_1_GPIO_BASE, LED_1_PIN, led_state_1);
        if(led_previous_1 != led_state_1) {
            led_previous_1 = led_state_1;
            demo_uart_write_string("RGB LED 1 GREEN ");
            demo_uart_write_string(led_state_1 ? "ON\r\n" : "OFF\r\n");
        }
        const int led_state_2 = button_state_2;
        write_output(LED_2_GPIO_BASE, LED_2_PIN, led_state_2);
        if(led_previous_2 != led_state_2) {
            led_previous_2 = led_state_2;
            demo_uart_write_string("RGB LED 1 BLUE ");
            demo_uart_write_string(led_state_2 ? "ON\r\n" : "OFF\r\n");
        }

        const int uart_rx = demo_uart_read_char();
        if(uart_rx >= 0) {
            demo_uart_write_string("UART RX: ");
            demo_uart_write_char((char)uart_rx);
            demo_uart_write_string("\r\n");
        }
    }
}
